# Create customer segments using RFM-like approach
# R = Recency (is_active), F = Frequency (tenure as proxy), M = Monetary (spend)

def assign_segment(row):
    """
    Assign customer segment based on activity, spending, and tenure
    """
    spend = row['monthly_spend_clean']
    is_active = row['is_active']
    tenure = row['tenure_days']
    plan = row['plan_tier']

    # High-value segments
    if spend >= 100:  # Enterprise-level spending
        if is_active:
            return 'Champions'
        else:
            return 'At-Risk High-Value'

    # Premium segments (50-100)
    elif spend >= 50:
        if is_active:
            return 'Loyal Customers'
        else:
            return 'At-Risk Premium'

    # Mid-tier segments (10-50)
    elif spend >= 10:
        if is_active:
            if tenure >= 365:
                return 'Loyal Customers'
            else:
                return 'Promising'
        else:
            return 'Needs Attention'

    # Low-spend active users
    elif spend > 0:
        if is_active:
            if tenure < 90:
                return 'New Users'
            else:
                return 'Casual Users'
        else:
            return 'Hibernating'

    # Zero spend
    else:
        if is_active:
            if tenure < 90:
                return 'New Users'
            else:
                return 'Free Riders'
        else:
            return 'Lost'

df['segment'] = df.apply(assign_segment, axis=1)

print("Segment distribution:")
print(df['segment'].value_counts())
